from azure.eventgrid import EventGridPublisherClient, EventGridEvent


def _env(name: str, default: Optional[str] = None) -> str:
    v = os.getenv(name, default)
    if v is None or v == "":
        raise ValueError(f"Missing required environment variable: {name}")
    return v


def _utc_iso() -> str:
    return datetime.datetime.utcnow().replace(tzinfo=datetime.timezone.utc).isoformat()


def _read_blob_text(blob_service: BlobServiceClient, container: str, blob_name: str, max_bytes: int) -> str:
    bc = blob_service.get_blob_client(container=container, blob=blob_name)
    downloader = bc.download_blob(max_concurrency=4)
    data = downloader.readall()
    if len(data) > max_bytes:
        data = data[:max_bytes]
    try:
        return data.decode("utf-8")
    except UnicodeDecodeError:
        return data.decode("utf-8", errors="replace")


def _basic_process(content: str) -> Dict[str, Any]:
    lines = content.splitlines()
    words = content.split()
    return {
        "charCount": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "preview": content[:512],
    }


def _ensure_cosmos_container(cosmos_client: CosmosClient, db_name: str, container_name: str):
    db = cosmos_client.create_database_if_not_exists(id=db_name)
    container = db.create_container_if_not_exists(
        id=container_name,
        partition_key=PartitionKey(path="/pk"),
        offer_throughput=400,
    )
    return container


def _publish_event(
    eg_client: EventGridPublisherClient,
    subject: str,
    event_type: str,
    data: Dict[str, Any],
    data_version: str = "1.0",
):
    evt = EventGridEvent(
        subject=subject,
        event_type=event_type,
        data=data,
        data_version=data_version,
    )
    eg_client.send([evt])


def main(event: func.EventGridEvent):
    logger = logging.getLogger("blob-to-cosmos-eg")
    logger.setLevel(logging.INFO)

    storage_account_url = _env("STORAGE_ACCOUNT_URL")
    cosmos_account_url = _env("COSMOS_ACCOUNT_URL")
    cosmos_db_name = _env("COSMOS_DB_NAME")
    cosmos_container_name = _env("COSMOS_CONTAINER_NAME")
    eventgrid_topic_endpoint = _env("EVENTGRID_TOPIC_ENDPOINT")

    max_blob_bytes = int(os.getenv("MAX_BLOB_BYTES", "1048576"))

    credential = DefaultAzureCredential()

    blob_service = BlobServiceClient(account_url=storage_account_url, credential=credential)
    cosmos_client = CosmosClient(url=cosmos_account_url, credential=credential)
    eg_client = EventGridPublisherClient(endpoint=eventgrid_topic_endpoint, credential=credential)

    container = _ensure_cosmos_container(cosmos_client, cosmos_db_name, cosmos_container_name)

    eg_data = event.get_json()
    url = eg_data.get("url") or eg_data.get("data", {}).get("url")
    if not url:
        raise ValueError("Event does not contain blob url")

    try:
        parsed = BlobServiceClient.from_blob_url(url)
        container_name = parsed.container_name
        blob_name = parsed.blob_name
    except Exception:
        from urllib.parse import urlparse

        u = urlparse(url)
        parts = u.path.lstrip("/").split("/", 1)
        if len(parts) != 2:
            raise ValueError(f"Unable to parse blob url: {url}")
        container_name, blob_name = parts[0], parts[1]

    logger.info("Processing blob: container=%s blob=%s", container_name, blob_name)

    content = _read_blob_text(blob_service, container_name, blob_name, max_blob_bytes)
    metrics = _basic_process(content)

